var $jq = jQuery.noConflict();
var data2 = [];

let apiResponseObj = {};
let processedData = [];
let columnsStructure = {};
let expandableStructure = {};
let $tableName = "";
let jsonObj = {};

let apiFlag = false;
let accordFlag = false;
api = "";
accordInit = "";

let newUrl = "";

let filterminprice;
let filtermaxprice;
let filterObj = {};
let filteredData = {};
let searchInput = "";
let autocompleteList = "";
let srchByFilterObj = {};
let $emptySrchMBarApi;
let $invalidPriceApi;
let pricefilterTriggered = false;
let srchpaginationID = "";
let apiUrl = "";
let coveocurrentPage = 1;
let pageSize = 12;
let clearAllFlag = false;
let isCheckboxChange = false;

let autoCompleteTimeout = null;
const AUTOCOMPLETE_DELAY = 300; // milliseconds
const MIN_CHARS_AUTOCOMPLETE = 2;
let switchEle = "";
let $mlCatEle = "";
let $mlModEle = "";
let srchPaginationElement;

$jq(document).ready(function(){
    $jq(window).on('popstate', function() {
         location.reload(true);
    });

    const uuidKey = 'clientId';

    let uuid = localStorage.getItem(uuidKey);

    if (!uuid) {
      uuid = generateUUID();
      localStorage.setItem(uuidKey, uuid);
    }

    function generateUUID() {
      return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        const r = Math.random() * 16 | 0,
              v = c === 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
      });
    }

    if($jq("#dy-table-pricefilter").length){
        initAccordion("dy-table-pricefilter");
    }

    if($jq("#dy-table-certswitch").length){
        initAccordion("dy-table-certswitch");
    }

    emptySrchMBar = document.getElementById("MessageBar-container-emptySrch");
	$emptySrchMBarApi = DDS.MessageBar(emptySrchMBar);
    $emptySrchMBarApi.hide();
    emptySrchMBar.classList.remove("dds__d-none");

    invalidPriceEle = document.getElementById("MessageBar-container-invalidPrice");
    $invalidPriceApi = DDS.MessageBar(invalidPriceEle);
    $invalidPriceApi.show();

    searchInput = document.getElementById('dds__srch-input');
    autocompleteList = document.getElementById('autocomplete-list');
    init();
    let isSrchFltrHintHidden = sessionStorage.getItem("hideSrchFltrHint");
    $jq(".dds__pagination__page-range-current").val("1");

    if (isSrchFltrHintHidden == "" || isSrchFltrHintHidden == null || isSrchFltrHintHidden == undefined){
		const srchFltrHintelement = document.getElementById("dds__msgBar-filterHint");
        const srchFltrHintInit = DDS.MessageBar(srchFltrHintelement);

        srchFltrHintInit.show();

        srchFltrHintelement.addEventListener("ddsMessageBarHiddenEvent", (e) => {
        	sessionStorage.setItem("hideSrchFltrHint", "true");
        });
	} else {
			const srchFltrHintelement = document.getElementById("dds__msgBar-filterHint");
            srchFltrHintelement.classList.add("dds__d-none");
    }

    $jq(".dds__icon--search").unbind('click').click(function(){
        if($jq("#dds__srch-input").val().trim() != "" && $jq("#dds__srch-input").val().trim() != null){
            logSearch(apiResponseObj);
            $emptySrchMBarApi.hide();
//            resetPagination();
            updateURL();
            init();
        } else {
    	    $emptySrchMBarApi.show();
        }
    });

    $jq("#dds__srch-input").unbind('keyup').keyup(function(event) {
        if (event.keyCode === 13) {
        if($jq("#dds__srch-input").val().trim() != "" && $jq("#dds__srch-input").val().trim() != null){
            logSearch(apiResponseObj);
            $emptySrchMBarApi.hide();
//            resetPagination();
            updateURL();
            init();
        } else {
        	$emptySrchMBarApi.show();
        }
        }
    });

    $jq(".dds__icon--close-cir").unbind('click').click(function(){
    	$jq("#dds__srch-input").val("");
        $emptySrchMBarApi.hide();
        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
        updateURL();
        var tagid = $jq(".dds__tag[data-cbmap=searchBy]").attr("id");
        var tagDiv = document.getElementById(tagid);
        var dismissButton = tagDiv.querySelector('button:nth-of-type(2)');

        dismissButton.click();
        init();
    });

    $jq(".dt-clear-all").off('click').on("click", function() {
        if ($jq(".dds__tag").length) {
            clearAllFlag = true;

            $jq(document).off('ddsTagDismissEvent');

            $jq(window).off('popstate');

            const tagsToRemove = [];
            $jq(".dds__tag").each(function() {
                tagsToRemove.push({
                    cbmap: $jq(this).data("cbmap"),
                    tagid: $jq(this).attr("id")
                });
            });

            const certSwitch = document.getElementById('dds__cert-switch');
            if (certSwitch) {
                certSwitch.removeEventListener('ddsSwitchChangeEvent', certSwitchHandler);
                if (certSwitch.getAttribute('aria-checked') === 'true') {
                    switchEle.toggleChecked();
                }
            }

            $jq("#dy-table-accordion-Categories .dds__checkbox__input:checked, #dy-table-accordion-Type .dds__checkbox__input:checked")
                .each(function() {
                    $jq(this).prop('checked', false);
                });

            $jq("#dds__srch-input").val("");

            $jq("#dds__price-min").val("");
            $jq("#dds__price-max").val("");

            tagsToRemove.forEach(tag => {
                $jq(`#${tag.tagid}`).remove();
            });

            $jq(".dds__price-error").addClass("dds__d-none");
            $jq(".filter-clearAll").addClass("dds__d-none");
            $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");

            coveocurrentPage = 1;
//            resetPagination();
            updatePaginationUI(1);
            $jq(".dds__pagination__range-start").text("1");
            $jq(".dds__pagination__range-end").text(pageSize);

            window.history.pushState(null, null, window.location.pathname);

            triggerStoreSearchAPI($jq.trim(apiUrl));

            const categoryMoreLess = document.querySelector('.dds__mlbtn-epcategory');
            const typeMoreLess = document.querySelector('.dds__mlbtn-epmodalitycourse');

            if (categoryMoreLess && categoryMoreLess.getAttribute('aria-expanded') === 'true') {
                if ($mlCatEle && typeof $mlCatEle.collapse === 'function') {
                    $mlCatEle.collapse();
                }
            }

            if (typeMoreLess && typeMoreLess.getAttribute('aria-expanded') === 'true') {
                if ($mlModEle && typeof $mlModEle.collapse === 'function') {
                    $mlModEle.collapse();
                }
            }

            setTimeout(function() {
                initTagEvents();

                if (certSwitch) {
                    certSwitch.addEventListener('ddsSwitchChangeEvent', certSwitchHandler);
                }

                $jq(window).on('popstate', function() {
                     location.reload(true);
                });

                clearAllFlag = false;
            }, 500);
        }
    });

    function initTagEvents() {
        $jq(".dds__tag").each(function() {
            const tagId = $jq(this).attr("id");
            const tagElement = document.getElementById(tagId);
            if (tagElement) {
                DDS.Tag(tagElement, { dismiss: true });
                tagElement.addEventListener("ddsTagDismissEvent", tagDismissHandler);
            }
        });
    }

  function tagDismissHandler(e) {
      if (isCheckboxChange || clearAllFlag) return;

      if(e.relatedTarget.dataset.cbmap == "searchBy") {
          searchInput.value = "";
          $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
      } else if(e.relatedTarget.dataset.cbmap == "priceRange") {
          $jq("#dds__price-min").val("");
          $jq("#dds__price-max").val("");
      } else {
          $jq("#"+e.relatedTarget.dataset.cbmap).prop('checked', false);
      }

      if($jq(".dds__tag").length == 1) {
          $jq(".filter-clearAll").addClass("dds__d-none");
      }

      const currentPageSize = parseInt($jq("#pagination-per-page-886179417").val() || pageSize);

      updateURL();
      coveocurrentPage = 1;
      pageSize = currentPageSize;

      init();
  }

    $jq("#dds__price-min").unbind('keyup').keyup(function(event) {
        if (event.keyCode === 13) {
    			applyPriceFilter();
        }
    });

    $jq("#dds__price-max").unbind('keyup').keyup(function(event) {
    	if (event.keyCode === 13) {
    		applyPriceFilter();
        }
    });

    $jq("#dds__srch-input").on('input', function() {
            const searchValue = this.value.trim();

            if (autoCompleteTimeout) {
                clearTimeout(autoCompleteTimeout);
            }

            if (searchValue === '') {
                $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
                hideAutocompleteList();
                return;
            }

            $jq("#dds__srch-inputWrapper .dds__icon--close-cir").removeClass("dds__d-none");

            if (searchValue.length >= MIN_CHARS_AUTOCOMPLETE) {
                autoCompleteTimeout = setTimeout(() => {
                    fetchAutocomplete(searchValue);
                }, AUTOCOMPLETE_DELAY);
            } else {
                hideAutocompleteList();
            }
        });

        $jq(document).on('click', function(event) {
            if (!$jq(event.target).closest('#dds__srch-input, #autocomplete-list').length) {
                hideAutocompleteList();
            }
        });

        $jq("#dds__srch-input").on('keydown', function(e) {
            if ($jq("#autocomplete-list").hasClass('dds__d-none')) {
                return;
            }

            const listItems = $jq("#autocomplete-list .dds__autocomplete-item");
            const currentIndex = listItems.index($jq(".dds__autocomplete-item--active"));

            switch(e.keyCode) {
                case 40:
                    e.preventDefault();
                    if (listItems.length > 0) {
                        if (currentIndex < 0 || currentIndex >= listItems.length - 1) {
                            listItems.removeClass("dds__autocomplete-item--active");
                            listItems.first().addClass("dds__autocomplete-item--active");
                        } else {
                            listItems.removeClass("dds__autocomplete-item--active");
                            listItems.eq(currentIndex + 1).addClass("dds__autocomplete-item--active");
                        }
                    }
                    break;

                case 38:
                    e.preventDefault();
                    if (listItems.length > 0) {
                        if (currentIndex <= 0) {
                            listItems.removeClass("dds__autocomplete-item--active");
                            listItems.last().addClass("dds__autocomplete-item--active");
                        } else {
                            listItems.removeClass("dds__autocomplete-item--active");
                            listItems.eq(currentIndex - 1).addClass("dds__autocomplete-item--active");
                        }
                    }
                    break;

                case 13:
                    e.preventDefault();
                    const activeItem = $jq(".dds__autocomplete-item--active");
                    if (activeItem.length) {
                        activeItem.click();
                        hideAutocompleteList();
                    }
                    break;

                case 27:
                    e.preventDefault();
                    hideAutocompleteList();
                    break;
            }
        });

        function certSwitchHandler(e) {
//            resetPagination();

            const originalExpanded = {};
            const categoryMoreLess = document.querySelector('.dds__mlbtn-epcategory');
            const typeMoreLess = document.querySelector('.dds__mlbtn-epmodalitycourse');

            if (categoryMoreLess) {
                originalExpanded.category = categoryMoreLess.getAttribute('aria-expanded') === 'true';
            }
            if (typeMoreLess) {
                originalExpanded.type = typeMoreLess.getAttribute('aria-expanded') === 'true';
            }

            triggerStoreSearchAPI($jq.trim(apiUrl));

            setTimeout(function() {
                const needCategoryExpanded = checkIfAnyFiltersSelected('epcategory', 5);
                const needTypeExpanded = checkIfAnyFiltersSelected('epmodalitycourse', 5);

                if (categoryMoreLess && !needCategoryExpanded && originalExpanded.category) {
                    if ($mlCatEle && typeof $mlCatEle.collapse === 'function') {
                        $mlCatEle.collapse();
                    }
                }

                if (typeMoreLess && !needTypeExpanded && originalExpanded.type) {
                    if ($mlModEle && typeof $mlModEle.collapse === 'function') {
                        $mlModEle.collapse();
                    }
                }
            }, 1000);
        }

        const certSwitchEle = document.getElementById("dds__cert-switch");
        switchEle = DDS.Switch(certSwitchEle);
        certSwitchEle.addEventListener('ddsSwitchChangeEvent', certSwitchHandler);

        window.addEventListener('popstate', function(event) {
            console.log('Back button pressed', window.location.href);
            updateFiltersFromURL();
        });

});

function checkIfAnyFiltersSelected(jNode, position) {
            const filterDivs = document.querySelectorAll(`.dds__srchby-filter-${jNode}`);

            if (filterDivs.length <= position) return false;

            for (var i = position; i < filterDivs.length; i++) {
                const checkbox = filterDivs[i].querySelector('input.dds__checkbox__input');
                if (checkbox && checkbox.checked) {
                    return true;
                }
            }
            return false;
        }

function init(){
    clearAllFlag = false;
    apiUrl = $jq(".tableApiUrl").text();
    if($mlCatEle){
        $mlCatEle.collapse();
    }
    if($mlModEle){
        $mlModEle.collapse();
    }
    if($jq.trim(apiUrl)){
        var tablePageType = $jq(".tablePageType").text();
        if (tablePageType == "storeSearch"){
            triggerStoreSearchAPI($jq.trim(apiUrl));
        }
    } else {
         console.log("API URL is missing");
    }
}

function getCertSwitchValue() {
    const certSwitch = document.getElementById('dds__cert-switch');
    return certSwitch && certSwitch.getAttribute('aria-checked') === 'true' ? 'Dell EMC Proven Professional' : '';
}

function triggerStoreSearchAPI(tableApiUrl) {

    const uiPageSize = parseInt($jq("#pagination-per-page-886179417").val());
        if (uiPageSize && !isNaN(uiPageSize)) {
            pageSize = uiPageSize;
        }

    $jq(".dds__no-resultsText").text("No results found for $srchText - please change your search criteria $srchAudText");
    $jq(".dds__api-error").addClass("dds__d-none");
    $jq(".dds__srch-data-loading").removeClass("dds__d-none");
    $jq(".dds__srch-data-container").addClass("dds__d-none");

    const priceMinInput = document.getElementById("dds__price-min");
    const priceMaxInput = document.getElementById("dds__price-max");

    const queryString = window.location.search.substring(1);
    const paramsArray = queryString.split("%26");
    const params = new URLSearchParams(paramsArray.join("&"));

    window.urlParams = {
        categories: params.get("c") ? params.get("c").split(",").map(item => DOMPurify.sanitize(item, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })) : [],
        types: params.get("t") ? params.get("t").split(",").map(item => DOMPurify.sanitize(item, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })) : [],
        price: DOMPurify.sanitize(params.get("p"), { ALLOWED_TAGS: [], ALLOWED_ATTR: [] }),
        searchText: params.get("x") ? DOMPurify.sanitize(decodeURIComponent(params.get("x")), { ALLOWED_TAGS: [], ALLOWED_ATTR: [] }) : ""
    };

    if (searchInput && window.urlParams.searchText) {
        searchInput.value = DOMPurify.sanitize(window.urlParams.searchText, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] });
        addFilterTag(searchInput, "searchBy");
        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").removeClass("dds__d-none");
    } else {
        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
    }

    if (window.urlParams.price) {
        const [minPrice, maxPrice] = window.urlParams.price === "FREE" ? ["0", "0"] : window.urlParams.price.split(" - ");
        if (priceMinInput) priceMinInput.value = String(minPrice).trim();
        if (priceMaxInput) priceMaxInput.value = String(maxPrice).trim();
        addFilterTag("", "priceRange");
    }

    const firstResult = (coveocurrentPage - 1) * pageSize;

    var usrLoc = $jq(".dt-emc-header").data("location") ? $jq(".dt-emc-header").data("location") : "United States";

    if ($jq(".dt-emc-header").data("audtype").toUpperCase() == "GUEST" || $jq(".dt-emc-header").data("audtype").toUpperCase() == "INTERNAL") {
        var locCookie = readCookie("location");
        usrLoc = locCookie ? locCookie : "United States";
    }

    let cq = `((@epaudiencetypes=="All" AND @eppriceListCode=="mpl" AND @epprice==0.0) OR (@epaudiencetypes=="${usrLoc}" AND @epcountry=="${usrLoc}")) AND (@epprice>=0 AND @epprice<99999999)`;

    if (window.urlParams.price) {
        const [minPrice, maxPrice] = window.urlParams.price === "FREE" ? ["0", "0"] : window.urlParams.price.split(" - ");
        cq = cq.replace("(@epprice>=0 AND @epprice<99999999)", `(@epprice>=${minPrice.trim()} AND @epprice<=${maxPrice.trim()}) AND (@epprice>=0 AND @epprice<99999999)`);
    }

    if (window.urlParams.categories.length > 0) {
        const categoriesCQ = window.urlParams.categories.map(cat => `@epcategory==\"${cat}\"`).join(" AND ");
        cq += ` AND (${categoriesCQ})`;
    }

    const certValue = getCertSwitchValue();
    if (certValue) {
        cq += ` AND (@epcustom2==\"${certValue}\")`;
    }

    if (window.urlParams.types.length > 0) {
        const typesCQ = window.urlParams.types.map(type => `@epmodalitycourse==\"${type}\"`).join(" AND ");
        cq += ` AND (${typesCQ})`;
    }

    var jsonObj = {
        "q": searchInput ? searchInput.value.trim() : "",
        "searchHub": "EducationHub",
        "sortCriteria": "relevancy",
        "sortField": "fielddescedning",
        "enableRankingInformation": true,
        "firstResult": firstResult,
        "numberOfResults": pageSize,
        "cq": cq,
        "facets": [
            {
                "facetId": "Category",
                "field": "epcategory",
                "type": "hierarchical",
                "sortCriteria": "alphanumeric",
                "injectionDepth": 1000,
                "delimitingCharacter": "|",
                "filterFacetCount": true,
                "basePath": [],
                "filterByBasePath": false,
                "currentValues": [],
                "preventAutoSelect": false,
                "numberOfValues": 100,
                "isFieldExpanded": false
            },
            {
                "facetId": "Modality",
                "field": "epmodalitycourse",
                "type": "hierarchical",
                "sortCriteria": "nosort",
                "injectionDepth": 1000,
                "delimitingCharacter": "|",
                "filterFacetCount": true,
                "basePath": [],
                "filterByBasePath": false,
                "currentValues": [],
                "preventAutoSelect": false,
                "numberOfValues": 100,
                "isFieldExpanded": false
            }
        ]
    };

    $jq.ajax({
        url: tableApiUrl,
        type: "POST",
        data: JSON.stringify(jsonObj),
        dataType: "json",
        cache: false,
        success: function (respObj) {
            processResponseObj(respObj);
        },
        error: function (errmsg) {
            console.log("error" + errmsg.d);
            setTimeout(function () {
                $jq(".dds__srch-data-loading").addClass("dds__d-none");
                $jq(".dds__srch-data-container").addClass("dds__d-none");
                $jq(".dds__api-error").removeClass("dds__d-none");
            }, 1000);
        }
    });
}

function fetchAutocomplete(searchText) {
    const context = encodeURIComponent(JSON.stringify({
        "lang": "English",
        "geo": "United States"
    }));

    const autoCompleteUrl = '/eduservice/cash.json/coveoautocomplete' +
        '?organizationId=dellsandbox2' +
        '&searchHub=EducationHub' +
        '&enableWordCompletion=false' +
        '&count=5' +
        '&context=' + context +
        '&limit=5' +
        '&q=' + encodeURIComponent(searchText);

    $jq.ajax({
        url: autoCompleteUrl,
        type: "GET",
        dataType: "json",
        cache: false,
        success: function(response) {
            if (response && response.completions && response.completions.length > 0) {
                showAutocompleteList(response.completions);
            } else {
                hideAutocompleteList();
            }
        },
        error: function(errmsg) {
            console.log("Autocomplete error:", errmsg);
            hideAutocompleteList();
        }
    });
}

function showAutocompleteList(completions) {
    if (!autocompleteList) return;

    autocompleteList.innerHTML = '';

    completions.forEach((item, index) => {
        const li = document.createElement('li');
        li.className = 'dds__autocomplete-item';
        if (index === 0) {
            li.className += ' dds__autocomplete-item--active';
        }
        li.textContent = item.expression;

        li.addEventListener('click', function() {
            searchInput.value = item.expression;
            hideAutocompleteList();
            $jq("#dds__srch-inputWrapper .dds__icon--close-cir").removeClass("dds__d-none");
            $jq(".dds__icon--search").trigger('click');
        });

        li.addEventListener('mouseover', function() {
            const items = autocompleteList.querySelectorAll('.dds__autocomplete-item');
            items.forEach(i => i.classList.remove('dds__autocomplete-item--active'));
            this.classList.add('dds__autocomplete-item--active');
        });

        autocompleteList.appendChild(li);
    });

    autocompleteList.classList.remove('dds__d-none');
}

function hideAutocompleteList() {
    if (autocompleteList) {
        autocompleteList.innerHTML = '';
        autocompleteList.classList.add('dds__d-none');
    }
}

function processResponseObj(respObj){
    if(respObj){

            apiResponseObj = respObj;
            if($jq("ul.tableFilters li").length > 0){
                $jq("ul.tableFilters li").each(function(){
                    if($jq(this).data("filtertype") == "filter-static"){
                        generateStaticFilter(apiResponseObj, eval('(' + $jq.trim($jq(this).text()) + ')'), $jq(this).data("filtertitle"), $jq(this).data("jnode"))
                    } else if($jq(this).data("filtertype") == "filter-dynamic"){
                        generateDynamicFilter(apiResponseObj, $jq.trim($jq(this).text()), $jq(this).data("filtertitle"), $jq(this).data("jnode"))
                    }
                });
            }
            if($jq(".tablePageType").text() == "storeSearch"){
                processData(apiResponseObj);

				$jq(".dds__srch-data-loading").addClass("dds__d-none");
                    $jq(".dds__srch-data-container").removeClass("dds__d-none");
            }


    } else {
        console.log("Error in processResponseObj function : " + respObj.message)
    }
}

function processData(jsonData){

    if (jsonData.totalCount > 0) {
        logPageLoad(apiResponseObj);
        filteredData = jsonData.results;
        totalCount = jsonData.totalCount
        const accordionContainer = document.getElementById('accordion-srch-container');
        	while (accordionContainer.firstChild) {
                accordionContainer.removeChild(accordionContainer.firstChild);
            }

        filteredData.forEach((item, index) => {
            const raw = item.raw;
            const accordionItem = document.createElement('div');
            accordionItem.className = 'dds__accordion__item dds__mb-4 dds__accordion__item--expanded';

            const heading = document.createElement('h4');
            heading.className = 'dds__accordion__heading';


            const link = document.createElement('a');
            link.id = `accordion-item-trigger-${raw.epcode}`;
            link.className = 'dds__accordion__button dds_srch_title_link';
            link.setAttribute('aria-controls', `accordion-item-content-${raw.epcode}`);

            if (raw.episcourseorpackage === "Course") {
                link.href = `/content/dell/en-us/home/store/search/course-details.html?courseID=${raw.epcode}%26mod=${raw.epmodalitycourse[0]}`;
            } else {
                link.href = `/content/dell/en-us/home/store/valuepak.html?code=${raw.epcode}`;
            }

            const title = document.createElement('h5');
            title.className = 'dds__srch-title';
            title.setAttribute('data-arrIndex', index);

            if (raw.epflag === 2) {
                const newBadge = document.createElement('span');
                newBadge.className = 'dds__badge dds__badge--md dds__srch-badge-new dds__mr-2';
                const newBadgeLabel = document.createElement('span');
                newBadgeLabel.className = 'dds__badge__label';
                newBadgeLabel.textContent = 'New';
                newBadge.appendChild(newBadgeLabel);
                title.appendChild(newBadge);
            }

            if (raw.epcustom2) {
                const certBadge = document.createElement('span');
                certBadge.className = 'dds__badge dds__badge--md dds__srch-badge-cert dds__mr-2 ace-bgcolor';
                const certBadgeLabel = document.createElement('span');
                certBadgeLabel.className = 'dds__badge__label';
                certBadgeLabel.textContent = 'Certification-aligned';
                certBadge.appendChild(certBadgeLabel);
                title.appendChild(certBadge);
            }

            const titleSpan = document.createElement('span');
            titleSpan.className = 'dds__srch-title-span';
            titleSpan.textContent = `${raw.systitle} >`;

