function handleUrlParamFilters(jNode, filterTitle) {
    console.log(`Starting handleUrlParamFilters for ${jNode} with title ${filterTitle}`);
    const urlParams = window.urlParams[jNode === "epcategory" ? "categories" : "types"];

    if (!urlParams || !urlParams.length) {
        console.log("No URL params found");
        return;
    }

    const subfiltersInUrl = [];
    const subfilterElements = document.querySelectorAll(`.dds__srchby-filter-${jNode} input[data-parent]`);

    subfilterElements.forEach(subfilter => {
        if (urlParams.includes(subfilter.value)) {
            subfiltersInUrl.push({
                element: subfilter,
                parentValue: subfilter.getAttribute('data-parent')
            });
        }
    });

    const parentsToExpand = [];

    subfiltersInUrl.forEach(({parentValue}) => {
        document.querySelectorAll(`.dds__srchby-filter-${jNode} input[value="${parentValue}"]:not([data-parent])`).forEach(parentInput => {
            const accordionItem = parentInput.closest('.dds__accordion__item');
            if (accordionItem) {
                const expandButton = accordionItem.querySelector('.dds__filter-parent-btn');
                if (expandButton && expandButton.getAttribute('aria-expanded') === 'false') {
                    const filterDivs = document.querySelectorAll(`.dds__srchby-filter-${jNode}`);
                    let parentIndex = -1;

                    filterDivs.forEach((div, index) => {
                        const input = div.querySelector(`input[value="${parentValue}"]:not([data-parent])`);
                        if (input) {
                            parentIndex = index;
                        }
                    });

                    parentsToExpand.push({
                        expandButton: expandButton,
                        isBeyondFive: parentIndex >= 5,
                        parentValue: parentValue
                    });
                }
            }
        });
    });

    const parentFilterDivs = document.querySelectorAll(`.dds__srchby-filter-${jNode}`);
    parentFilterDivs.forEach((div, index) => {
        if (index >= 5) {
            const input = div.querySelector('input.dds__checkbox__input');
            if (input && urlParams.includes(input.value) && div.hasAttribute('hidden')) {
                console.log(`Found direct filter match beyond position 5: ${input.value}`);
                parentsToExpand.push({
                    expandButton: null,
                    isBeyondFive: true,
                    parentValue: input.value
                });
            }
        }
    });

    const needViewMore = parentsToExpand.some(p => p.isBeyondFive);

    setTimeout(() => {
        if (needViewMore) {
            const moreButton = document.querySelector(`.dds__mlbtn-${jNode}`);

            if (moreButton) {
                console.log(`Found View More button for ${jNode}, clicking...`);
                try {
                    $jq(moreButton).click();

                    setTimeout(() => {
                        expandParentAccordions();
                    }, 500);
                } catch (e) {
                    console.error(`Error clicking View More button for ${jNode}:`, e);
                    expandParentAccordions();
                }
            } else {
                console.log(`View More button not found for ${jNode}`);
                expandParentAccordions();
            }
        } else {
            console.log(`No need to click View More for ${jNode}, expanding parents directly`);
            expandParentAccordions();
        }
    }, 700);

    function expandParentAccordions() {
        parentsToExpand.forEach(({expandButton, parentValue}) => {
            if (expandButton) {
                try {
                    console.log(`Clicking expand button for ${parentValue} in ${jNode}`);
                    $jq(expandButton).click();
                } catch (e) {
                    console.error(`Error clicking expand button for ${parentValue} in ${jNode}:`, e);
                }
            }
        });
    }
}
