    DDS.Tag(tagelement, { dismiss: true });

    tagelement.addEventListener("ddsTagDismissEvent", (e) => {
        if (isCheckboxChange) return;

        if(e.relatedTarget.dataset.cbmap == "searchBy") {
            searchInput.value = "";
            $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
        } else if(e.relatedTarget.dataset.cbmap == "priceRange") {
            $jq("#dds__price-min").val("");
            $jq("#dds__price-max").val("");
        } else {
            $jq("#"+e.relatedTarget.dataset.cbmap).prop('checked', false);
        }

        if($jq(".dds__tag").length == 1) {
            $jq(".filter-clearAll").addClass("dds__d-none");
        }

        updateURL();
        if(!clearAllFlag) {
            resetPagination();
            init();
        }
    });
}

function updateURL() {
    const categoryCheckboxes = Array.from(document.querySelectorAll("#dy-table-accordion-Categories .dds__checkbox__input:checked"));
    const categories = categoryCheckboxes.map(checkbox => checkbox.value).join(',');

    const typeCheckboxes = Array.from(document.querySelectorAll("#dy-table-accordion-Type .dds__checkbox__input:checked"));
    const types = typeCheckboxes.map(checkbox => checkbox.value).join(',');

    const priceMinInput = document.getElementById("dds__price-min");
    const priceMaxInput = document.getElementById("dds__price-max");
    const minPrice = priceMinInput.value.trim() ? priceMinInput.value.trim() : "";
    const maxPrice = priceMaxInput.value.trim() ? priceMaxInput.value.trim() : "";
    let price = "";
    if(minPrice && maxPrice){
        price = (minPrice === "0" && maxPrice === "0") ? "FREE" : `${minPrice} - ${maxPrice}`;
    }

    const searchInput = document.getElementById("dds__srch-input");
    const searchText = searchInput ? encodeURIComponent(searchInput.value.trim()) : "";

    let queryParams = [];
    if (categories) queryParams.push(`c=${categories}`);
    if (types) queryParams.push(`t=${types}`);
    if (price) queryParams.push(`p=${price}`);
    if (searchText) queryParams.push(`x=${searchText}`);

    const queryString = queryParams.join('%26');
    clearAllFlag = false;

    newUrl = `${window.location.origin}${window.location.pathname}?${queryString}`;
    window.history.pushState(null, null, newUrl);

}

